#include<bits/stdc++.h>
using namespace std;
long long n;
long long ans=0;
int main(){
    cin>>n;
    for(int i=1;;i++){
        if(n-7*i<=0){
            ans+=(n/i);
            if(n%i!=0) ans++;
            break;
        }else{
            n-=7*i;
            ans+=7;
        }
    }
    cout<<ans;
}
